import json
import random
from typing import Dict, List, Optional, Tuple

class MarkovChain:
    def __init__(self, order: int = 1):
        self.order = order
        self.transitions: Dict[str, Dict[str, int]] = {}

    @staticmethod
def train(text: str, model_path: str) -> None:
    with open(model_path, 'w') as f:
        mc = MarkovChain()
        mc.train(text)
        json.dump(mc.to_dict(), f)

    def generate(self, length: int, seed: Optional[str] = None, random_seed: Optional[int] = None) -> str:
        if not seed and not random_seed:
            return self._generate(length)
        elif seed:
            random.seed(seed)
        elif random_seed:
            random.seed(random_seed)
        return self._generate(length)

    def _generate(self, length: int) -> str:
        context = tuple([random.choice(list(self.transitions.keys()))] * self.order)
        result = ''.join(context)
        for _ in range(length - self.order):
            next_char = random.choices(list(self.transitions[context]), weights=list(self.transitions[context].values()), k=1)[0]
            result += next_char
            context = tuple([next_char] + list(context[:-1]))
        return result

    def to_dict(self) -> Dict[str, Any]:
        return {
            'order': self.order,
            'transitions': self.transitions
        }

    @classmethod
def from_dict(cls, d: Dict[str, Any]) -> 'MarkovChain':
        mc = cls()
        mc.order = d['order']
        mc.transitions = d['transitions']
        return mc
